mapper.insert:
insert into anime (
    name, original_name, cover_url, total_episodes, type, source_type,
    release_year, season, synopsis, source_provider, source_subject_id, created_by
) values (
    #{name}, #{originalName}, #{coverUrl}, #{totalEpisodes}, #{type}, #{sourceType},
    #{releaseYear}, #{season}, #{synopsis}, #{sourceProvider}, #{sourceSubjectId}, #{createdBy}
)

mapper.select:
select *
from anime
where source_provider = #{sourceProvider}
  and source_subject_id = #{sourceSubjectId}
limit 1

select * from anime where name = #{name}
and release_year = #{releaseYear}
and release_year is null
order by id desc limit 1

mapper.update:
update anime
set original_name = case
                        when #{originalName} is not null and #{originalName} != '' then #{originalName}
                        else original_name
                    end,
    cover_url = case
                    when #{coverUrl} is not null and #{coverUrl} != '' then #{coverUrl}
                    else cover_url
                end,
    total_episodes = case
                         when #{totalEpisodes} is not null and #{totalEpisodes} > 0 then #{totalEpisodes}
                         else total_episodes
                     end,
    type = case
               when #{type} is not null and #{type} != '' then #{type}
               else type
           end,
    source_type = case
                      when #{sourceType} is not null and #{sourceType} != '' then #{sourceType}
                      else source_type
                  end,
    source_provider = case
                          when #{sourceProvider} is not null and #{sourceProvider} != '' then #{sourceProvider}
                          else source_provider
                      end,
    source_subject_id = case
                            when #{sourceSubjectId} is not null then #{sourceSubjectId}
                            else source_subject_id
                        end,
    release_year = case
                       when #{releaseYear} is not null then #{releaseYear}
                       else release_year
                   end,
    season = case
                 when #{season} is not null and #{season} != '' then #{season}
                 else season
             end,
    synopsis = case
                   when #{synopsis} is not null and #{synopsis} != '' then #{synopsis}
                   else synopsis
               end
where id = #{id}
